public abstract class Asset {
    private String description;
    private String dateAcquired;
    private double originalCost;

    public Asset(String description, String dateAcquired, double originalCost) {
        this.description = description;
        this.dateAcquired = dateAcquired;
        this.originalCost = originalCost;
    }

    public String getDescription() { return description; }
    public double getOriginalCost() { return originalCost; }

    public abstract double getCurrentValue();
}

public class House extends Asset {
    @Override
    public double getCurrentValue() { /* house-specific logic */ return 0; }
}

public class Vehicle extends Asset {
    @Override
    public double getCurrentValue() { /* vehicle-specific logic */ return 0; }
}

public class House extends Asset {
    private double squareFootage;
    private double lotSize;
    private String condition; // "excellent", "good", "poor"

    public House(String description, String dateAcquired, double originalCost,
                 double squareFootage, double lotSize, String condition) {
        super(description, dateAcquired, originalCost);
        this.squareFootage = squareFootage;
        this.lotSize = lotSize;
        this.condition = condition;
    }

    @Override
    public double getCurrentValue() {
        double pricePerSqFt = switch (condition.toLowerCase()) {
            case "excellent" -> 180.0;
            case "poor"      -> 95.0;
            default          -> 135.0;
        };
        return (squareFootage * pricePerSqFt) + (lotSize * 500.0);
    }
}

public class Vehicle extends Asset {
    private int year;
    private String make;
    private double mileage;

    public Vehicle(String description, String dateAcquired, double originalCost,
                   int year, String make, double mileage) {
        super(description, dateAcquired, originalCost);
        this.year = year;
        this.make = make;
        this.mileage = mileage;
    }

    @Override
    public double getCurrentValue() {
        int age = 2025 - year;
        double value = getOriginalCost();
        if (age <= 2)       value *= 0.85;
        else if (age <= 5)  value *= 0.65;
        else if (age <= 10) value *= 0.40;
        else                value *= 0.20;
        if (mileage > 100000) value *= 0.90;
        if (make.equalsIgnoreCase("Honda") || make.equalsIgnoreCase("Toyota")) value *= 1.10;
        return value;
    }
}

