public abstract class BankAccount {
    protected double balance;

    public void deposit(double amount) { if (amount > 0) balance += amount; }
    public boolean withdraw(double amount) {
        if (amount > 0 && amount <= balance) { balance -= amount; return true; }
        return false;
    }
    public abstract double getMonthlyFee();
}

public class CheckingAccount extends BankAccount {
    @Override
    public double getMonthlyFee() { return balance >= 1000 ? 0 : 12.00; }
}

public class SavingsAccount extends BankAccount {
    @Override
    public double getMonthlyFee() { return balance >= 500 ? 0 : 5.00; }
}

public abstract class Character {
    protected String name;
    protected int baseAttack;

    public Character(String name, int baseAttack) {
        this.name = name;
        this.baseAttack = baseAttack;
    }

    public abstract int calculateDamage();
}

public class Warrior extends Character {
    public Warrior(String name, int baseAttack) { super(name, baseAttack); }
    @Override
    public int calculateDamage() { return baseAttack * 2; }
}

public class Mage extends Character {
    private int spellPower;
    public Mage(String name, int baseAttack, int spellPower) {
        super(name, baseAttack);
        this.spellPower = spellPower;
    }
    @Override
    public int calculateDamage() { return super.baseAttack + (spellPower * 3); }
}
